export default function render(node) {
  if (node == null) return document.createTextNode('');
  if (typeof node === 'string' || typeof node === 'number') {
    return document.createTextNode(String(node));
  }
  const el = document.createElement(node.type);
  const props = node.props || {};
  for (const [key, value] of Object.entries(props)) {
    if (value == null) continue;
    if (key === 'className') el.setAttribute('class', String(value));
    else el.setAttribute(key, String(value));
  }
  const children = node.children;
  if (Array.isArray(children)) {
    children.forEach((child) => el.appendChild(render(child)));
  } else if (children != null) {
    el.appendChild(render(children));
  }
  return el;
}
